rss.channel:
{% set channel_title = "RSS Feed | " ~ config.title %}
    {% set channel_description = config.description %}
    {% set channel_link = config.base_url %}
    {% if title is defined and title != "" %}
      {% set channel_title = title %}
    {% endif %}
    {% if description is defined and description != "" %}
      {% set channel_description = description %}
    {% endif %}
    {% if feed_url is defined and (feed_url is containing("/tags/")) %}
      {% set tag_name = feed_url | replace(from=config.base_url ~ "/tags/", to="") | replace(from="/rss.xml", to="") %}
      {% if tag_name != "" and not (tag_name is containing("http")) %}
        {% set channel_title = "Tag: " ~ tag_name ~ " | " ~ config.title %}
        {% set channel_description = "Posts tagged with " ~ tag_name ~ "." %}
      {% endif %}
    {% endif %}
    {% if feed_url is defined and (feed_url is containing("/categories/")) %}
      {% set category_name = feed_url | replace(from=config.base_url ~ "/categories/", to="") | replace(from="/rss.xml", to="") %}
      {% if category_name != "" and not (category_name is containing("http")) %}
        {% set channel_title = "Category: " ~ category_name ~ " | " ~ config.title %}
        {% set channel_description = "Posts in " ~ category_name ~ "." %}
      {% endif %}
    {% endif %}
    {% if current_url is defined and current_url != "" %}
      {% set channel_link = current_url %}
    {% elif feed_url is defined and feed_url != "" %}
      {% set channel_link = feed_url | replace(from="rss.xml", to="") %}
    {% endif %}
    {{ channel_title }}
    {{ channel_link }}
    {{ channel_description }}
    Zola
    {{ config.default_language }}

    {{ last_updated | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {% for page in pages %}


        {{ page.title }}
        {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
        {{ config.author }}
        {{ page.permalink }}
        {{ page.permalink }}
        {% if page.summary %}{{ page.summary | safe }}{% elif page.description %}{{ page.description }}{% else %}{{ page.content }}{% endif %}

    {% endfor %}
